const data = $input.first().json.body;

// Validate required fields
if (!data.clientEmail || !data.service || !data.requirements) {
  return [{ json: { error: 'Missing required fields' } }];
}

// Calculate pricing
const pricing = {
  website: { base: 1500, perPage: 300, rush: 500 },
  ecommerce: { base: 3500, perProduct: 10, perFeature: 500 },
  webapp: { base: 5000, perFeature: 1000 },
  marketing: { base: 1000, perChannel: 500 }
};

const service = pricing[data.service] || pricing.website;
let total = service.base;

// Add-ons
const addons = [];
if (data.pages > 5) {
  const extra = (data.pages - 5) * service.perPage;
  total += extra;
  addons.push({ name: `Extra Pages (${data.pages - 5})`, price: extra });
}
if (data.rush) {
  total += service.rush;
  addons.push({ name: 'Rush Delivery (5 days)', price: service.rush });
}
if (data.features) {
  data.features.forEach(f => {
    total += service.perFeature;
    addons.push({ name: f, price: service.perFeature });
  });
}

return [{
  json: {
    ...data,
    basePrice: service.base,
    addons: addons,
    totalPrice: total,
    advancePayment: Math.round(total * 0.5),
    finalPayment: Math.round(total * 0.5)
  }
}];

